def _new(self, im):
    new = Image()
    new.im = im
    new.mode = im.mode
    new._size = im.size
    if im.mode in ("P", "PA"):
        if self.palette:
            new.palette = self.palette.copy()
        else:
            from . import ImagePalette

            new.palette = ImagePalette.ImagePalette()
    new.info = self.info.copy()
    return new

# Context manager support
def __enter__(self):
    return self

def __exit__(self, *args):
    if hasattr(self, "fp") and getattr(self, "_exclusive_fp", False):
        if hasattr(self, "_close__fp"):
            self._close__fp()
        if self.fp:
            self.fp.close()
    self.fp = None

def close(self):
    """
    Closes the file pointer, if possible.

    This operation will destroy the image core and release its memory.
    The image data will be unusable afterward.

    This function is required to close images that have multiple frames or
    have not had their file read and closed by the
    :py:meth:`~PIL.Image.Image.load` method. See :ref:`file-handling` for
    more information.
    """
    try:
        if hasattr(self, "_close__fp"):
            self._close__fp()
        if self.fp:
            self.fp.close()
        self.fp = None
    except Exception as msg:
        logger.debug("Error closing: %s", msg)

    if getattr(self, "map", None):
        self.map = None

    # Instead of simply setting to None, we're setting up a
    # deferred error that will better explain that the core image
    # object is gone.
    self.im = deferred_error(ValueError("Operation on closed image"))

def _copy(self):
    self.load()
    self.im = self.im.copy()
    self.pyaccess = None
    self.readonly = 0

def _ensure_mutable(self):
    if self.readonly:
        self._copy()
    else:
        self.load()

def _dump(self, file=None, format=None, **options):
    suffix = ""
    if format:
        suffix = "." + format

    if not file:
        f, filename = tempfile.mkstemp(suffix)
        os.close(f)
    else:
        filename = file
        if not filename.endswith(suffix):
            filename = filename + suffix

    self.load()

    if not format or format == "PPM":
        self.im.save_ppm(filename)
    else:
        self.save(filename, format, **options)

    return filename

def __eq__(self, other):
    return (
        self.__class__ is other.__class__
        and self.mode == other.mode
        and self.size == other.size
        and self.info == other.info
        and self._category == other._category
        and self.readonly == other.readonly
        and self.getpalette() == other.getpalette()
        and self.tobytes() == other.tobytes()
    )

def __repr__(self):
    return "<%s.%s image mode=%s size=%dx%d at 0x%X>" % (
        self.__class__.__module__,
        self.__class__.__name__,
        self.mode,
        self.size[0],
        self.size[1],
        id(self),
    )

def _repr_png_(self):
    """iPython display hook support

    :returns: png version of the image as bytes
    """
    b = io.BytesIO()
    try:
        self.save(b, "PNG")
    except Exception as e:
        raise ValueError("Could not save to PNG for display") from e
    return b.getvalue()

class _ArrayData:
    def __init__(self, new):
        self.__array_interface__ = new

def __array__(self, dtype=None):
    # numpy array interface support
    import numpy as np

    new = {}
    shape, typestr = _conv_type_shape(self)
    new["shape"] = shape
    new["typestr"] = typestr
    new["version"] = 3
    if self.mode == "1":
        # Binary images need to be extended from bits to bytes
        # See: https://github.com/python-pillow/Pillow/issues/350
        new["data"] = self.tobytes("raw", "L")
    else:
        new["data"] = self.tobytes()

    return np.array(self._ArrayData(new), dtype)

def __getstate__(self):
    return [self.info, self.mode, self.size, self.getpalette(), self.tobytes()]

def __setstate__(self, state):
    Image.__init__(self)
    self.tile = []
    info, mode, size, palette, data = state
    self.info = info
    self.mode = mode
    self._size = size
    self.im = core.new(mode, size)
    if mode in ("L", "LA", "P", "PA") and palette:
        self.putpalette(palette)
    self.frombytes(data)

def tobytes(self, encoder_name="raw", *args):
    """
    Return image as a bytes object.

    .. warning::

        This method returns the raw image data from the internal
        storage.  For compressed image data (e.g. PNG, JPEG) use
        :meth:`~.save`, with a BytesIO parameter for in-memory
        data.

    :param encoder_name: What encoder to use.  The default is to
                         use the standard "raw" encoder.
    :param args: Extra arguments to the encoder.
    :returns: A :py:class:`bytes` object.
    """

    # may pass tuple instead of argument list
    if len(args) == 1 and isinstance(args[0], tuple):
        args = args[0]

    if encoder_name == "raw" and args == ():
        args = self.mode

    self.load()

    # unpack data
    e = _getencoder(self.mode, encoder_name, args)
    e.setimage(self.im)

    bufsize = max(65536, self.size[0] * 4)  # see RawEncode.c

    data = []
    while True:
        l, s, d = e.encode(bufsize)
        data.append(d)
        if s:
            break
    if s < 0:
        raise RuntimeError(f"encoder error {s} in tobytes")

    return b"".join(data)

def tobitmap(self, name="image"):
    """
    Returns the image converted to an X11 bitmap.

    .. note:: This method only works for mode "1" images.

    :param name: The name prefix to use for the bitmap variables.
    :returns: A string containing an X11 bitmap.
    :raises ValueError: If the mode is not "1"
    """

    self.load()
    if self.mode != "1":
        raise ValueError("not a bitmap")
    data = self.tobytes("xbm")
    return b"".join(
        [
            f"#define {name}_width {self.size[0]}\n".encode("ascii"),
            f"#define {name}_height {self.size[1]}\n".encode("ascii"),
            f"static char {name}_bits[] = {{\n".encode("ascii"),
            data,
            b"};",
        ]
    )

def frombytes(self, data, decoder_name="raw", *args):
    """
    Loads this image with pixel data from a bytes object.

    This method is similar to the :py:func:`~PIL.Image.frombytes` function,
    but loads data into this image instead of creating a new image object.
    """

    # may pass tuple instead of argument list
    if len(args) == 1 and isinstance(args[0], tuple):
        args = args[0]

    # default format
    if decoder_name == "raw" and args == ():
        args = self.mode

    # unpack data
    d = _getdecoder(self.mode, decoder_name, args)
    d.setimage(self.im)
    s = d.decode(data)

    if s[0] >= 0:
        raise ValueError("not enough image data")
    if s[1] != 0:
        raise ValueError("cannot decode image data")

def load(self):
    """
    Allocates storage for the image and loads the pixel data.  In
    normal cases, you don't need to call this method, since the
    Image class automatically loads an opened image when it is
    accessed for the first time.

    If the file associated with the image was opened by Pillow, then this
    method will close it. The exception to this is if the image has
    multiple frames, in which case the file will be left open for seek
    operations. See :ref:`file-handling` for more information.

    :returns: An image access object.
    :rtype: :ref:`PixelAccess` or :py:class:`PIL.PyAccess`
    """
    if self.im and self.palette and self.palette.dirty:
        # realize palette
        mode, arr = self.palette.getdata()
        if mode == "RGBA":
            mode = "RGB"
            self.info["transparency"] = arr[3::4]
            arr = bytes(
                value for (index, value) in enumerate(arr) if index % 4 != 3
            )
        palette_length = self.im.putpalette(mode, arr)
        self.palette.dirty = 0
        self.palette.rawmode = None
        if "transparency" in self.info and mode in ("RGBA", "LA", "PA"):
            if isinstance(self.info["transparency"], int):
                self.im.putpalettealpha(self.info["transparency"], 0)
            else:
                self.im.putpalettealphas(self.info["transparency"])
            self.palette.mode = "RGBA"
        else:
            self.palette.mode = "RGB"
            self.palette.palette = self.im.getpalette()[: palette_length * 3]

    if self.im:
        if cffi and USE_CFFI_ACCESS:
            if self.pyaccess:
                return self.pyaccess
            from . import PyAccess

            self.pyaccess = PyAccess.new(self, self.readonly)
            if self.pyaccess:
                return self.pyaccess
        return self.im.pixel_access(self.readonly)

def verify(self):
    """
    Verifies the contents of a file. For data read from a file, this
    method attempts to determine if the file is broken, without
    actually decoding the image data.  If this method finds any
    problems, it raises suitable exceptions.  If you need to load
    the image after using this method, you must reopen the image
    file.
    """
    pass

def convert(self, mode=None, matrix=None, dither=None, palette=WEB, colors=256):
    """
    Returns a converted copy of this image. For the "P" mode, this
    method translates pixels through the palette.  If mode is
    omitted, a mode is chosen so that all information in the image
    and the palette can be represented without a palette.

    The current version supports all possible conversions between
    "L", "RGB" and "CMYK." The ``matrix`` argument only supports "L"
    and "RGB".

    When translating a color image to greyscale (mode "L"),
    the library uses the ITU-R 601-2 luma transform::

        L = R * 299/1000 + G * 587/1000 + B * 114/1000

    The default method of converting a greyscale ("L") or "RGB"
    image into a bilevel (mode "1") image uses Floyd-Steinberg
    dither to approximate the original image luminosity levels. If
    dither is :data:`NONE`, all values larger than 127 are set to 255 (white),
    all other values to 0 (black). To use other thresholds, use the
    :py:meth:`~PIL.Image.Image.point` method.

    When converting from "RGBA" to "P" without a ``matrix`` argument,
    this passes the operation to :py:meth:`~PIL.Image.Image.quantize`,
    and ``dither`` and ``palette`` are ignored.

    :param mode: The requested mode. See: :ref:`concept-modes`.
    :param matrix: An optional conversion matrix.  If given, this
       should be 4- or 12-tuple containing floating point values.
    :param dither: Dithering method, used when converting from
       mode "RGB" to "P" or from "RGB" or "L" to "1".
       Available methods are :data:`NONE` or :data:`FLOYDSTEINBERG` (default).
       Note that this is not used when ``matrix`` is supplied.
    :param palette: Palette to use when converting from mode "RGB"
       to "P".  Available palettes are :data:`WEB` or :data:`ADAPTIVE`.
    :param colors: Number of colors to use for the :data:`ADAPTIVE` palette.
       Defaults to 256.
    :rtype: :py:class:`~PIL.Image.Image`
    :returns: An :py:class:`~PIL.Image.Image` object.
    """

    self.load()

    has_transparency = self.info.get("transparency") is not None
    if not mode and self.mode == "P":
        # determine default mode
        if self.palette:
            mode = self.palette.mode
        else:
            mode = "RGB"
        if mode == "RGB" and has_transparency:
            mode = "RGBA"
    if not mode or (mode == self.mode and not matrix):
        return self.copy()

    if matrix:
        # matrix conversion
        if mode not in ("L", "RGB"):
            raise ValueError("illegal conversion")
        im = self.im.convert_matrix(mode, matrix)
        new = self._new(im)
        if has_transparency and self.im.bands == 3:
            transparency = new.info["transparency"]

            def convert_transparency(m, v):
                v = m[0] * v[0] + m[1] * v[1] + m[2] * v[2] + m[3] * 0.5
                return max(0, min(255, int(v)))

            if mode == "L":
                transparency = convert_transparency(matrix, transparency)
            elif len(mode) == 3:
                transparency = tuple(
                    convert_transparency(matrix[i * 4 : i * 4 + 4], transparency)
                    for i in range(0, len(transparency))
                )
            new.info["transparency"] = transparency
        return new

    if mode == "P" and self.mode == "RGBA":
        return self.quantize(colors)

    trns = None
    delete_trns = False
    # transparency handling
    if has_transparency:
        if self.mode in ("1", "L", "I", "RGB") and mode == "RGBA":
            # Use transparent conversion to promote from transparent
            # color to an alpha channel.
            new_im = self._new(
                self.im.convert_transparent(mode, self.info["transparency"])
            )
            del new_im.info["transparency"]
            return new_im
        elif self.mode in ("L", "RGB", "P") and mode in ("L", "RGB", "P"):
            t = self.info["transparency"]
            if isinstance(t, bytes):
                # Dragons. This can't be represented by a single color
                warnings.warn(
                    "Palette images with Transparency expressed in bytes should be "
                    "converted to RGBA images"
                )
                delete_trns = True
            else:
                # get the new transparency color.
                # use existing conversions
                trns_im = Image()._new(core.new(self.mode, (1, 1)))
                if self.mode == "P":
                    trns_im.putpalette(self.palette)
                    if isinstance(t, tuple):
                        err = "Couldn't allocate a palette color for transparency"
                        try:
                            t = trns_im.palette.getcolor(t, self)
                        except ValueError as e:
                            if str(e) == "cannot allocate more than 256 colors":
                                # If all 256 colors are in use,
                                # then there is no need for transparency
                                t = None
                            else:
                                raise ValueError(err) from e
                if t is None:
                    trns = None
                else:
                    trns_im.putpixel((0, 0), t)

                    if mode in ("L", "RGB"):
                        trns_im = trns_im.convert(mode)
                    else:
                        # can't just retrieve the palette number, got to do it
                        # after quantization.
                        trns_im = trns_im.convert("RGB")
                    trns = trns_im.getpixel((0, 0))

        elif self.mode == "P" and mode in ("LA", "PA", "RGBA"):
            t = self.info["transparency"]
            delete_trns = True

            if isinstance(t, bytes):
                self.im.putpalettealphas(t)
            elif isinstance(t, int):
                self.im.putpalettealpha(t, 0)
            else:
                raise ValueError("Transparency for P mode should be bytes or int")

    if mode == "P" and palette == ADAPTIVE:
        im = self.im.quantize(colors)
        new = self._new(im)
        from . import ImagePalette

        new.palette = ImagePalette.ImagePalette("RGB", new.im.getpalette("RGB"))
        if delete_trns:
            # This could possibly happen if we requantize to fewer colors.
            # The transparency would be totally off in that case.
            del new.info["transparency"]
        if trns is not None:
            try:
                new.info["transparency"] = new.palette.getcolor(trns, new)
            except Exception:
                # if we can't make a transparent color, don't leave the old
                # transparency hanging around to mess us up.
                del new.info["transparency"]
                warnings.warn("Couldn't allocate palette entry for transparency")
        return new

    # colorspace conversion
    if dither is None:
        dither = FLOYDSTEINBERG

    try:
        im = self.im.convert(mode, dither)
    except ValueError:
        try:
            # normalize source image and try again
            im = self.im.convert(getmodebase(self.mode))
            im = im.convert(mode, dither)
        except KeyError as e:
            raise ValueError("illegal conversion") from e

    new_im = self._new(im)
    if mode == "P" and palette != ADAPTIVE:
        from . import ImagePalette

        new_im.palette = ImagePalette.ImagePalette("RGB", list(range(256)) * 3)
    if delete_trns:
        # crash fail if we leave a bytes transparency in an rgb/l mode.
        del new_im.info["transparency"]
    if trns is not None:
        if new_im.mode == "P":
            try:
                new_im.info["transparency"] = new_im.palette.getcolor(trns, new_im)
            except ValueError as e:
                del new_im.info["transparency"]
                if str(e) != "cannot allocate more than 256 colors":
                    # If all 256 colors are in use,
                    # then there is no need for transparency
                    warnings.warn(
                        "Couldn't allocate palette entry for transparency"
                    )
        else:
            new_im.info["transparency"] = trns
    return new_im

def quantize(self, colors=256, method=None, kmeans=0, palette=None, dither=1):
    """
    Convert the image to 'P' mode with the specified number
    of colors.

    :param colors: The desired number of colors, <= 256
    :param method: :data:`MEDIANCUT` (median cut),
                   :data:`MAXCOVERAGE` (maximum coverage),
                   :data:`FASTOCTREE` (fast octree),
                   :data:`LIBIMAGEQUANT` (libimagequant; check support using
                   :py:func:`PIL.features.check_feature`
                   with ``feature="libimagequant"``).

